INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-7fec267e-moex-00914', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '甲男乙女為夫妻，有丙、丁二子。丙有戊、己二子。丙先於甲死亡。甲死亡時，戊依法拋棄繼承。己之 應繼分為何？', '["三分之一", "四分之一", "五分之一", "六分之一"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00915', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '關於刑事訴訟法第155條第2項所定「無證據能力、未經合法調查之證據，不得作為判斷之依據。」下 列敘述何者正確？', '["這是證據之證明力的規定", "證據能力是由法院本於確信自由判斷", "這是關於嚴格證明的規定", "只要經過合法調查的證據資料，均有證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00916', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '檢察官以被告甲在警詢中自白、購毒者乙在偵查中之證言等證據，起訴甲販賣毒品罪。甲在第一審受命 法官準備程序期日，陳述其在警詢時之自白，是被強暴脅迫所為，下列何人要就甲在警詢中係出於自由 意志之自白，指出證明方法？', '["甲", "檢察官", "法官", "乙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00917', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '被告經法官訊問後，犯罪嫌疑重大，而有羈押原因，非予羈押顯難進行訴訟。然下列何項原因，不得單 獨成為羈押被告原因？', '["逃亡或有事實足認為有逃亡之虞者", "有事實足認為有湮滅、偽造、變造證據或勾串共犯或證人之虞者", "所犯為死刑、無期徒刑或最輕本刑為五年以上有期徒刑之罪者", "所犯為死刑、無期徒刑或最輕本刑為五年以上有期徒刑之罪，有相當理由認為有逃亡、湮滅、偽造、 變造證據或勾串共犯或證人之虞者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00918', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何項供述，依刑事訴訟法規定有證據能力？', '["被告在警察詢問時，依自由意志所為供述", "檢察官未為權利告知，訊問後被告所為供述", "檢察官不待被告通知之律師到場，訊問後被告所為供述", "被告於警詢被刑求取供後，隨即被移送檢察官，檢察官立刻訊問後被告所為供述"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00919', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者不屬刑法第21條第1項規定依法令之行為？', '["司法警察逮捕通緝犯", "路人甲逮捕現行犯", "父母管教滿20歲之子女", "檢察官執行死刑"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00920', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者非屬刑法第22條規定之業務上正當行為？', '["醫生為病人開刀", "拳擊手依比賽規則打傷對方", "棒球投手故意投觸身球傷害打擊者", "護士為病人打針"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00921', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '有關刑法第23條正當防衛之敘述，下列何者正確？', '["侵害已經結束，仍得主張正當防衛", "互毆可以主張正當防衛", "對警察依法逮捕之行為可以主張正當防衛", "防衛行為過當者，得減輕或免除其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00922', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '下列何者非屬於刑法第24條（緊急避難）明文列出之利益？', '["生命", "財產", "名譽", "自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL),
  ('elementary-7fec267e-moex-00923', 'elementary-7fec267e', 'elementary-7fec267e-moex-110-55d283b0', 'sub-elementary-7fec267e-03', NULL, 'single_choice', '有關刑法第62條自首之敘述，下列何者錯誤？', '["自首必減輕其刑", "自首可以言詞或書面為之", "自首可請人代理向警察機關為之", "通緝犯自行投案，不是自首"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:02+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "501", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "一般行政"}'::jsonb, NULL)
